    auto secondPtr = counter.operator->();
    secondPtr->add(delta);
    const int afterSecond = counter().current();

    return PointerAccessSnapshot{
        .valueAfterFirstAdd = afterFirst,
        .valueAfterSecondAdd = afterSecond,
        .pointerStable = firstPtr == secondPtr,
    };
}

